```csharp
private void Update()
{
    if (rayPerception != null)
    {
        List<float> rayObservations = rayPerception.Perceive(rayPerception.Sensor.Perceive());
        RaycastHit2D hit;
        for (int i = 0; i < rayPerception.RayAngles.Length; i++)
        {
            float angle = rayPerception.RayAngles[i] + transform.eulerAngles.z;
